args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wikibase: <http://wikiba.se/ontology#>

SELECT ?tree ?name
WHERE {
  ?tree wdt:P31 wd:Q1672;
        wdt:P170 wd:Q180736;
        wdt:P528 ?volume.
  ?volume wikibase:quantityAmount ?value.
  FILTER(?value > 912.5)
  OPTIONAL { ?tree rdfs:label ?name . FILTER(LANG(?name) = "en") }
}

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX wikibase: <http://wikiba.se/ontology#>

SELECT ?tree ?name ?value
WHERE {
  ?tree p:P1333 ?statement;
         wdt:P31 wd:Q167334.
  ?statement ps:P1333 ?volume.
  ?volume wikibase:quantityAmount ?value.
  FILTER(?value > 912.5)
  OPTIONAL { ?tree rdfs:label ?name . FILTER(LANG(?name) = "en") }
}
